<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Kanban Board</title>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  body {
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
    background: #0f172a;
    color: #e2e8f0;
    min-height: 100vh;
    padding: 32px 24px;
  }

  h1 {
    text-align: center;
    font-size: 1.75rem;
    font-weight: 700;
    letter-spacing: -0.02em;
    margin-bottom: 28px;
    color: #f1f5f9;
  }

  .add-row {
    display: flex;
    gap: 10px;
    max-width: 480px;
    margin: 0 auto 36px;
  }

  #new-card {
    flex: 1;
    padding: 10px 14px;
    border-radius: 10px;
    border: 1.5px solid #334155;
    background: #1e293b;
    color: #f1f5f9;
    font-size: 0.95rem;
    outline: none;
    transition: border-color 0.15s;
  }

  #new-card:focus { border-color: #6366f1; }

  #add-card {
    padding: 10px 20px;
    border-radius: 10px;
    border: none;
    background: #6366f1;
    color: #fff;
    font-size: 0.95rem;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s, transform 0.1s;
  }

  #add-card:hover { background: #4f46e5; }
  #add-card:active { transform: scale(0.97); }

  .board {
    display: flex;
    gap: 20px;
    align-items: flex-start;
    max-width: 1100px;
    margin: 0 auto;
  }

  .column {
    flex: 1;
    border-radius: 14px;
    background: #1e293b;
    border: 1.5px solid #2d3e52;
    display: flex;
    flex-direction: column;
    min-height: 200px;
    transition: border-color 0.15s;
  }

  .column.drag-over {
    border-color: #6366f1;
    background: #1e2d45;
  }

  .col-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 16px 18px 12px;
    border-bottom: 1.5px solid #2d3e52;
  }

  .col-title {
    font-weight: 700;
    font-size: 0.9rem;
    text-transform: uppercase;
    letter-spacing: 0.06em;
  }

  #col-todo .col-title { color: #94a3b8; }
  #col-doing .col-title { color: #f59e0b; }
  #col-done .col-title { color: #22c55e; }

  .count {
    background: #334155;
    color: #94a3b8;
    font-size: 0.78rem;
    font-weight: 700;
    padding: 2px 8px;
    border-radius: 999px;
    min-width: 24px;
    text-align: center;
  }

  .card-container {
    padding: 12px;
    display: flex;
    flex-direction: column;
    gap: 10px;
    min-height: 80px;
    flex: 1;
  }

  .card {
    background: #273549;
    border: 1.5px solid #334155;
    border-radius: 10px;
    padding: 12px 14px;
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: 10px;
    cursor: grab;
    transition: box-shadow 0.15s, border-color 0.15s, transform 0.1s;
    user-select: none;
  }

  .card:hover {
    border-color: #475569;
    box-shadow: 0 4px 16px rgba(0,0,0,0.3);
  }

  .card.dragging {
    opacity: 0.45;
    cursor: grabbing;
    transform: scale(0.98);
  }

  .card-title {
    font-size: 0.92rem;
    line-height: 1.45;
    color: #e2e8f0;
    word-break: break-word;
    flex: 1;
  }

  .card-del {
    flex-shrink: 0;
    background: none;
    border: none;
    color: #475569;
    cursor: pointer;
    font-size: 1rem;
    line-height: 1;
    padding: 2px 4px;
    border-radius: 6px;
    transition: color 0.15s, background 0.15s;
  }

  .card-del:hover {
    color: #f87171;
    background: #3b2a2a;
  }

  @media (max-width: 640px) {
    .board { flex-direction: column; }
  }
</style>
</head>
<body>

<h1>Kanban Board</h1>

<div class="add-row">
  <input id="new-card" type="text" placeholder="New card title…" autocomplete="off">
  <button id="add-card">Add Card</button>
</div>

<div class="board">
  <div class="column" id="col-todo">
    <div class="col-header">
      <span class="col-title">To Do</span>
      <span class="count">0</span>
    </div>
    <div class="card-container"></div>
  </div>
  <div class="column" id="col-doing">
    <div class="col-header">
      <span class="col-title">Doing</span>
      <span class="count">0</span>
    </div>
    <div class="card-container"></div>
  </div>
  <div class="column" id="col-done">
    <div class="col-header">
      <span class="col-title">Done</span>
      <span class="count">0</span>
    </div>
    <div class="card-container"></div>
  </div>
</div>

<script>
  const STORAGE_KEY = 'kanban_v1';
  const COLS = ['col-todo', 'col-doing', 'col-done'];

  let draggedCard = null;

  function getContainer(colId) {
    return document.getElementById(colId).querySelector('.card-container');
  }

  function updateCount(colId) {
    const col = document.getElementById(colId);
    const n = col.querySelectorAll('.card').length;
    col.querySelector('.count').textContent = n;
  }

  function updateAllCounts() {
    COLS.forEach(updateCount);
  }

  function saveState() {
    const state = COLS.map(colId => ({
      col: colId,
      cards: [...getContainer(colId).querySelectorAll('.card')].map(c =>
        c.querySelector('.card-title').textContent
      )
    }));
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }

  function createCard(title) {
    const card = document.createElement('div');
    card.className = 'card';
    card.draggable = true;

    const span = document.createElement('span');
    span.className = 'card-title';
    span.textContent = title;

    const del = document.createElement('button');
    del.className = 'card-del';
    del.title = 'Delete card';
    del.textContent = '✕';
    del.addEventListener('click', () => {
      const colId = card.closest('.column').id;
      card.remove();
      updateCount(colId);
      saveState();
    });

    card.appendChild(span);
    card.appendChild(del);

    card.addEventListener('dragstart', e => {
      draggedCard = card;
      card.classList.add('dragging');
      e.dataTransfer.effectAllowed = 'move';
    });

    card.addEventListener('dragend', () => {
      card.classList.remove('dragging');
      draggedCard = null;
      document.querySelectorAll('.column').forEach(c => c.classList.remove('drag-over'));
    });

    return card;
  }

  function addCard(colId, title, save = true) {
    if (!title.trim()) return;
    const card = createCard(title.trim());
    getContainer(colId).appendChild(card);
    updateCount(colId);
    if (save) saveState();
  }

  COLS.forEach(colId => {
    const col = document.getElementById(colId);

    col.addEventListener('dragover', e => {
      e.preventDefault();
      e.dataTransfer.dropEffect = 'move';
      col.classList.add('drag-over');
    });

    col.addEventListener('dragleave', e => {
      if (!col.contains(e.relatedTarget)) {
        col.classList.remove('drag-over');
      }
    });

    col.addEventListener('drop', e => {
      e.preventDefault();
      col.classList.remove('drag-over');
      if (!draggedCard) return;

      const fromCol = draggedCard.closest('.column');
      const container = getContainer(colId);

      // Insert before the card under the cursor if any
      const afterEl = getDragAfterElement(container, e.clientY);
      if (afterEl) {
        container.insertBefore(draggedCard, afterEl);
      } else {
        container.appendChild(draggedCard);
      }

      if (fromCol) updateCount(fromCol.id);
      updateCount(colId);
      saveState();
    });
  });

  function getDragAfterElement(container, y) {
    const cards = [...container.querySelectorAll('.card:not(.dragging)')];
    return cards.reduce((closest, child) => {
      const box = child.getBoundingClientRect();
      const offset = y - box.top - box.height / 2;
      if (offset < 0 && offset > closest.offset) {
        return { offset, element: child };
      }
      return closest;
    }, { offset: -Infinity }).element;
  }

  document.getElementById('add-card').addEventListener('click', () => {
    const input = document.getElementById('new-card');
    addCard('col-todo', input.value);
    input.value = '';
    input.focus();
  });

  document.getElementById('new-card').addEventListener('keydown', e => {
    if (e.key === 'Enter') document.getElementById('add-card').click();
  });

  // Load persisted state
  function loadState() {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return;
    try {
      const state = JSON.parse(raw);
      state.forEach(({ col, cards }) => {
        if (!COLS.includes(col)) return;
        cards.forEach(title => addCard(col, title, false));
      });
    } catch (e) {
      // corrupted storage — start fresh
      localStorage.removeItem(STORAGE_KEY);
    }
  }

  loadState();
</script>
</body>
</html>
